<div class="page-header"><div><h2 class="page-title">Creer un article</h2><p class="page-meta">Saisissez le contenu a publier.</p></div></div><form action="/admin/articles"class="card form-card"method="post"><div class="form-field"><label for="title">Titre</label> <input class="form-input"id="title"name="title"required></div><div class="form-field"><label for="content">Contenu</label> <textarea class="form-textarea"id="content"name="content"required rows="8"></textarea></div><div class="form-field"><label for="status">Statut</label> <select class="form-select"id="status"name="status"><option value="draft">Brouillon</option><option value="published">Publie</option></select></div><button class="btn btn-primary"type="submit">Enregistrer</button></form>